module branch_predictor(  
    input clk,  
    input reset,  
    input branch_outcome,  
    output reg prediction  
);  
    reg [1:0] prediction_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            prediction_counter <= 2'b00; // Start at Strongly Not Taken  
            prediction <= 1'b0;  
        end else begin  
            prediction <= prediction_counter[1]; // Output prediction based on MSB of prediction_counter  
            case (prediction_counter)  
                2'b00: if (branch_outcome) prediction_counter <= 2'b01; else prediction_counter <= 2'b00;  
                2'b01: if (branch_outcome) prediction_counter <= 2'b10; else prediction_counter <= 2'b00;  
                2'b10: if (branch_outcome) prediction_counter <= 2'b11; else prediction_counter <= 2'b01;  
                2'b11: if (branch_outcome) prediction_counter <= 2'b11; else prediction_counter <= 2'b10;  
                default: prediction_counter <= 2'b00;  
            endcase  
        end  
    end  
endmodule
